47:         /// <remarks>
48:         /// This method finds the best common type of a set of expressions as per section 7.5.2.14 of the specification.
49:         /// NOTE: If some or all of the expressions have error types, we return error type as the inference result.
50:         /// </remarks>
51:         public static TypeSymbol? InferBestType(
52:             ImmutableArray<BoundExpression> exprs,
53:             ConversionsBase conversions,
54:             ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo,
55:             out bool inferredFromFunctionType)
56:         {
57:             // SPEC:    7.5.2.14 Finding the best common type of a set of expressions
58:             // SPEC:    In some cases, a common type needs to be inferred for a set of expressions. In particular, the element types of implicitly typed arrays and
59:             // SPEC:    the return types of anonymous functions with block bodies are found in this way.
60:             // SPEC:    Intuitively, given a set of expressions E1…Em this inference should be equivalent to calling a method:
61:             // SPEC:        T M<X>(X x1 … X xm)
62:             // SPEC:    with the Ei as arguments. 
63:             // SPEC:    More precisely, the inference starts out with an unfixed type variable X. Output type inferences are then made from each Ei to X.
64:             // SPEC:    Finally, X is fixed and, if successful, the resulting type S is the resulting best common type for the expressions.
65:             // SPEC:    If no such S exists, the expressions have no best common type.
66: 
67:             // All non-null types are candidates for best type inference.
68:             IEqualityComparer<TypeSymbol> comparer = conversions.IncludeNullability ? Symbols.SymbolEqualityComparer.ConsiderEverything : Symbols.SymbolEqualityComparer.IgnoringNullable;
69:             HashSet<TypeSymbol> candidateTypes = new HashSet<TypeSymbol>(comparer);
70:             foreach (BoundExpression expr in exprs)
71:             {
72:                 Debug.Assert(!NullableWalker.IsTargetTypedExpression(expr));
73:                 TypeSymbol? type = expr.GetTypeOrFunctionType();
74: 
75:                 if (type is { })
76:                 {
77:                     if (type.ContainsErrorType())
78:                     {
79:                         if (type is FunctionTypeSymbol function)
80:                         {
81:                             inferredFromFunctionType = true;
82:                             return function.GetInternalDelegateType();
83:                         }
84:                         else
85:                         {
86:                             inferredFromFunctionType = false;
87:                             return type;
88:                         }
89:                     }
90: 
91:                     candidateTypes.Add(type);
92:                 }
93:             }
94: 
95:             // Perform best type inference on candidate types.
96:             var builder = ArrayBuilder<TypeSymbol>.GetInstance(candidateTypes.Count);
97:             builder.AddRange(candidateTypes);
98:             var result = GetBestType(builder, conversions, ref useSiteInfo);
99:             builder.Free();
