27:         private readonly struct ParameterMap
28:         {
29:             private readonly int[] _parameters;
30:             private readonly int _length;
31: 
32:             public ParameterMap(int[] parameters, int length)
33:             {
34:                 Debug.Assert(parameters == null || parameters.Length == length);
35:                 _parameters = parameters;
36:                 _length = length;
37:             }
38: 
39:             public bool IsTrivial { get { return _parameters == null; } }
40: 
41:             public int Length { get { return _length; } }
42: 
43:             public int this[int argument]
44:             {
45:                 get
46:                 {
47:                     Debug.Assert(0 <= argument && argument < _length);
48:                     return _parameters == null ? argument : _parameters[argument];
49:                 }
50:             }
51: 
52:             public ImmutableArray<int> ToImmutableArray()
53:             {
54:                 return _parameters.AsImmutableOrNull();
55:             }
