59:             Symbol symbol,
60:             AnalyzedArguments arguments,
61:             bool isMethodGroupConversion,
62:             bool expanded)
63:         {
64:             Debug.Assert((object)symbol != null);
65:             Debug.Assert(arguments != null);
66: 
67:             ImmutableArray<ParameterSymbol> parameters = symbol.GetParameters();
68:             bool isVararg = symbol.GetIsVararg();
69: 
70:             // The easy out is that we have no named arguments and are in normal form.
71:             if (!expanded && arguments.Names.Count == 0)
72:             {
73:                 return AnalyzeArgumentsForNormalFormNoNamedArguments(parameters, arguments, isMethodGroupConversion, isVararg);
74:             }
75: 
76:             // We simulate an additional non-optional parameter for a vararg method.
77: 
78:             int argumentCount = arguments.Arguments.Count;
79: 
80:             int[] parametersPositions = null;
81:             int? unmatchedArgumentIndex = null;
82:             bool? unmatchedArgumentIsNamed = null;
83: 
84:             // Try to map every argument position to a formal parameter position:
85: 
86:             bool seenNamedParams = false;
87:             bool seenOutOfPositionNamedArgument = false;
88:             for (int argumentPosition = 0; argumentPosition < argumentCount; ++argumentPosition)
89:             {
90:                 // We use -1 as a sentinel to mean that no parameter was found that corresponded to this argument.
