92:                 int parameterPosition = CorrespondsToAnyParameter(parameters, expanded, arguments, argumentPosition,
93:                     isVararg, out isNamedArgument, ref seenNamedParams, ref seenOutOfPositionNamedArgument) ?? -1;
94: 
95:                 if (parameterPosition == -1 && unmatchedArgumentIndex == null)
96:                 {
97:                     unmatchedArgumentIndex = argumentPosition;
98:                     unmatchedArgumentIsNamed = isNamedArgument;
99:                 }
